import sys

def main():
    if len(sys.argv) != 2:
        print("Usage: python script.py <fasta_file>")
        return
    fasta_file = sys.argv[1]
    sequences = []
    overall_gc = 0
    overall_total = 0
    current_seq_id = None
    current_gc = 0
    current_total = 0
    with open(fasta_file, 'r') as f:
        for line in f:
            line = line.rstrip('\n')
            if line.startswith('>'):
                if current_seq_id is not None:
                    if current_total > 0:
                        seq_gc = (current_gc / current_total) * 100
                    else:
                        seq_gc = 0.0
                    sequences.append((current_seq_id, seq_gc))
                    overall_gc += current_gc
                    overall_total += current_total
                seq_id_part = line.split('>')[1].split()[0]
                current_seq_id = seq_id_part
                current_gc = 0
                current_total = 0
            else:
                for char in line:
                    char_upper = char.upper()
                    if char_upper in {'A', 'C', 'G', 'T'}:
                        if char_upper in {'G', 'C'}:
                            current_gc += 1
                        current_total += 1
    if current_seq_id is not None:
        if current_total > 0:
            seq_gc = (current_gc / current_total) * 100
        else:
            seq_gc = 0.0
        sequences.append((current_seq_id, seq_gc))
        overall_gc += current_gc
        overall_total += current_total
    overall_percent = 0.0
    if overall_total > 0:
        overall_percent = (overall_gc / overall_total) * 100
    for seq_id, gc_percent in sequences:
        print(f"{seq_id}\t{gc_percent:.2f}")
    print(f"OVERALL\t{overall_percent:.2f}")

if __name__ == '__main__':
    main()

